mapper.select:
SELECT i.id, i.application_id, i.interview_time, i.location, i.interviewer_id, IFNULL(su.real_name, i.interviewer_name) AS interviewerName, i.status, i.evaluation, i.create_time, i.update_time, u.real_name AS candidateName, j.title AS jobTitle FROM interview i LEFT JOIN application a ON i.application_id = a.id AND a.deleted = 0 LEFT JOIN job_post j ON a.job_id = j.id AND j.deleted = 0 LEFT JOIN sys_user u ON a.candidate_id = u.id AND u.deleted = 0 LEFT JOIN sys_user su ON i.interviewer_id = su.id AND su.deleted = 0
AND i.status = #{query.status}
AND i.interviewer_id = #{query.interviewerId}
AND i.interview_time >= #{query.startTime}
AND i.interview_time <= #{query.endTime}
AND u.real_name LIKE CONCAT('%', #{query.candidateName}, '%')
AND a.candidate_id = #{query.candidateId}
ORDER BY i.interview_time DESC
